effect.shader:
        #define STEPS 50

        float noise( in vec3 x )
        {
            vec3 p = floor(x);
            vec3 f = fract(x);
            f = f*f*(3.0-2.0*f);
            vec2 uv = (p.xy+vec2(37.0,17.0)*p.z) + f.xy;
            uv = (uv+0.5)/256.0;
            vec2 rg = texture2D( rgbanoise.texture, uv ).yx;
            return mix( rg.x, rg.y, f.z );
        }

		float fbm( vec3 p ) {
            return noise(p)/2.
                + noise(p*2.)/4.
                + noise(p*4.)/8.
                + noise(p*8.)/16.
                ;
        }

        vec4 comp( vec4 bg, vec4 fg ) {
            return bg * (1.-fg.a) + fg;
        }

        float calcDensity(vec3 p) {
            //p.y *= 1.;
            float density = max(0.,fbm(p) - densityParam);
            return density;
        }


        void main() {

            vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
            vec2 st = acLayerNorm;
            st -= 0.5;
            st.x *= acLayerSize.x/acLayerSize.y;

            vec3 ro = camera/100.;
            vec3 rd = normalize(vec3(st, 1.));

            vec3 dd = rd / float(STEPS) * 6.;

            vec4 color = vec4(0.);

            vec3 light = vec3(20.0,120.0,-200.5);
            float radius = 1.464;

            for( int i=0; i<STEPS; i++ ) {
                vec3 p = ro + dd * float(i);
                vec3 lightDir = normalize(light-p);
                float t = 1.-float(i)/float(STEPS);
                float density = calcDensity(p);
                float lightGrad = density - calcDensity(p+lightDir*dd);
                vec4 c = mix(lightColor,shadowColor,lightGrad*6. - densityParam);
                //vec4 c = lightColor;
                density *= smoothstep(0.2,0.50,t);
                color = comp(c*density,color);
            }

            gl_FragColor = comp(texColor * fill,color * texColor.a);
        }
